455	/*
456	 * @section Packet Handler
457	 *
458	 * @text The packet handler is used to:
459	 *        - stop the counter after a disconnect
460	 *        - send a notification when the requested ATT_EVENT_CAN_SEND_NOW is received
461	 */
462	
463	/* LISTING_START(packetHandler): Packet Handler */
464	static void cbk_packet_handler(uint8_t packet_type, uint16_t channel, uint8_t *packet, uint16_t size)
465	{
466	    int mtu;
467	    u32 tmp;
468	    u8 status;
469	    const char *attribute_name;
470		STATUS *p_tone = get_tone_config();
471	    switch (packet_type) {
472	    case HCI_EVENT_PACKET:
473	        switch (hci_event_packet_get_type(packet)) {
474	
475	        /* case DAEMON_EVENT_HCI_PACKET_SENT: */
476	        /* break; */
477	        case ATT_EVENT_HANDLE_VALUE_INDICATION_COMPLETE:
478	            log_info("ATT_EVENT_HANDLE_VALUE_INDICATION_COMPLETE\n");
479	        case ATT_EVENT_CAN_SEND_NOW:
480	            can_send_now_wakeup();
481	            break;
482	
483	        case HCI_EVENT_LE_META:
484	            switch (hci_event_le_meta_get_subevent_code(packet)) {
485	            case HCI_SUBEVENT_LE_ENHANCED_CONNECTION_COMPLETE:
486					
487	                status = hci_subevent_le_enhanced_connection_complete_get_status(packet);
488	                if (status) {
489	                    log_info("LE_SLAVE CONNECTION FAIL!!! %0x\n", status);
490	                    set_ble_work_state(BLE_ST_DISCONN);
491	                    break;
492	                }
493	                con_handle = hci_subevent_le_enhanced_connection_complete_get_connection_handle(packet);
494	                log_info("HCI_SUBEVENT_LE_ENHANCED_CONNECTION_COMPLETE : %0x\n", con_handle);
495	                log_info("conn_interval = %d\n", hci_subevent_le_enhanced_connection_complete_get_conn_interval(packet));
496	                log_info("conn_latency = %d\n", hci_subevent_le_enhanced_connection_complete_get_conn_latency(packet));
497	                log_info("conn_timeout = %d\n", hci_subevent_le_enhanced_connection_complete_get_supervision_timeout(packet));
498	                server_profile_start(con_handle);
499	                break;
500	
501	            case HCI_SUBEVENT_LE_CONNECTION_COMPLETE:
502					clk_set("sys", (96 * 1000000L));
503					printf("HJX malloc EEP\n");
504					if(!gHJXEEPPointer)
505					{
506						gHJXEEPPointer=(u8 *)malloc(EEP_SIZE);
507						memset(gHJXEEPPointer,0,EEP_SIZE);
508						//if(gHJXHAPInfo.writeflag)
509						{
510							s_HJXRead70132K(gHJXEEPPointer,0,EEP_SIZE);
511							
512						}
513					}
514					
515					s_HJXHAP150SW(1);
516					s_HJXPostMsg(C_HJX_KEY_VALUE3,KEY_EVENT_DOUBLE_CLICK);
517	        		
518					s_SetLED(C_BLEDON);
519					gBLEConFlag=1;
520	                con_handle = hci_subevent_le_connection_complete_get_connection_handle(packet);
521	                log_info("HCI_SUBEVENT_LE_CONNECTION_COMPLETE: %0x\n", con_handle);
522	                connection_update_complete_success(packet + 8);
523	                server_profile_start(con_handle);
524	#if RCSP_BTMATE_EN
525	#if (defined(BT_CONNECTION_VERIFY) && (0 == BT_CONNECTION_VERIFY))
526	                JL_rcsp_auth_reset();
527	#endif
528	                //rcsp_dev_select(RCSP_BLE);
529	                rcsp_init();
530	#endif
531	                log_info("ble remote rssi= %d\n", ble_vendor_get_peer_rssi(con_handle));
532	                break;
533	
534	            case HCI_SUBEVENT_LE_CONNECTION_UPDATE_COMPLETE:
535	                connection_update_complete_success(packet);
536	                break;
537	
538	            case HCI_SUBEVENT_LE_DATA_LENGTH_CHANGE:
539	                log_info("APP HCI_SUBEVENT_LE_DATA_LENGTH_CHANGE\n");
540	                /* set_connection_data_phy(CONN_SET_CODED_PHY, CONN_SET_CODED_PHY); */
541	                break;
542	
543	            case HCI_SUBEVENT_LE_PHY_UPDATE_COMPLETE:
544	                log_info("APP HCI_SUBEVENT_LE_PHY_UPDATE %s\n", hci_event_le_meta_get_phy_update_complete_status(packet) ? "Fail" : "Succ");
545	                log_info("Tx PHY: %s\n", phy_result[hci_event_le_meta_get_phy_update_complete_tx_phy(packet)]);
546	                log_info("Rx PHY: %s\n", phy_result[hci_event_le_meta_get_phy_update_complete_rx_phy(packet)]);
547	                break;
548	            }
549	            break;
550	
551	        case HCI_EVENT_DISCONNECTION_COMPLETE:
552	            log_info("HCI_EVENT_DISCONNECTION_COMPLETE: %0x\n", packet[5]);
553				printf("HJX malloc free\n");
554				clk_set("sys", (24 * 1000000L));
555				s_HJXPostMsg(C_HJX_KEY_VALUE3,KEY_EVENT_TRIPLE_CLICK);
556				free(gHJXEEPPointer);
557				if(hjx_var.bleflag==1)
558					s_SetLED(C_BLEDFASTFLASH);
559				gHJXEEPPointer=NULL;
560				gBLEConFlag=0;
561	#if RCSP_BTMATE_EN
562	            rcsp_exit();
563	#endif
564	            con_handle = 0;
565	            ble_op_att_send_init(con_handle, 0, 0, 0);
566	            set_ble_work_state(BLE_ST_DISCONN);
567	
568	            if (!ble_update_get_ready_jump_flag()) {
569	                bt_ble_adv_enable(1);
570	            }
571	            connection_update_cnt = 0;
572	#if BT_FOR_APP_EN
573	            set_app_connect_type(TYPE_NULL);
574	#endif
575	            ble_auto_shut_down_enable(1);
576	            break;
577	
578	        case ATT_EVENT_MTU_EXCHANGE_COMPLETE:
