862	static int app_send_user_data(u16 handle, u8 *data, u16 len, u8 handle_type)
863	{
864	    u32 ret = APP_BLE_NO_ERROR;
865	
866	    if (!con_handle) {
867	        return APP_BLE_OPERATION_ERROR;
868	    }
869	
870	    if (!att_get_ccc_config(handle + 1)) {
871	        log_info("fail,no write ccc!!!,%04x\n", handle + 1);
872	        return APP_BLE_NO_WRITE_CCC;
873	    }
874	
875	    ret = ble_op_att_send_data(handle, data, len, handle_type);
876	    if (ret == BLE_BUFFER_FULL) {
877	        ret = APP_BLE_BUFF_FULL;
878	    }
879	
880	    if (ret) {
881	        log_info("app_send_fail:%d !!!!!!\n", ret);
882	    }
883	    return ret;
884	}
