1225	static int set_adv_enable(void *priv, u32 en)
1226	{
1227	    ble_state_e next_state, cur_state;
1228	
1229	    if (!adv_ctrl_en) {
1230	        return APP_BLE_OPERATION_ERROR;
1231	    }
1232	
1233	    if (con_handle) {
1234	        return APP_BLE_OPERATION_ERROR;
1235	    }
1236	
1237	    if (en) {
1238	        next_state = BLE_ST_ADV;
1239	    } else {
1240	        next_state = BLE_ST_IDLE;
1241	    }
1242	
1243	    cur_state =  get_ble_work_state();
1244	    switch (cur_state) {
1245	    case BLE_ST_ADV:
1246	    case BLE_ST_IDLE:
1247	    case BLE_ST_INIT_OK:
1248	    case BLE_ST_NULL:
1249	    case BLE_ST_DISCONN:
1250	        break;
1251	    default:
1252	        return APP_BLE_OPERATION_ERROR;
1253	        break;
1254	    }
1255	
1256	    if (cur_state == next_state) {
1257	        return APP_BLE_NO_ERROR;
1258	    }
1259	    log_info("adv_en:%d\n", en);
1260	    set_ble_work_state(next_state);
1261	
1262	#if EXT_ADV_MODE_EN
1263	    if (en) {
1264	        ble_op_set_ext_adv_param(&ext_adv_param, sizeof(ext_adv_param));
1265	
1266	        log_info_hexdump(&ext_adv_data, sizeof(ext_adv_data));
1267	        ble_op_set_ext_adv_data(&ext_adv_data, sizeof(ext_adv_data));
1268	
1269	        ble_op_set_ext_adv_enable(&ext_adv_enable, sizeof(ext_adv_enable));
1270	    } else {
1271	        ble_op_set_ext_adv_enable(&ext_adv_disable, sizeof(ext_adv_disable));
1272	    }
1273	#else
1274	    if (en) {
1275	        advertisements_setup_init();
1276	    }
1277	    ble_op_adv_enable(en);
1278	#endif /* EXT_ADV_MODE_EN */
1279	
1280	    return APP_BLE_NO_ERROR;
1281	}
